INSERT INTO ontology_nodes VALUES
    ('cube:orders', 'cube', 'orders', 'Product line-items per order — one row per product fulfilled. Use this cube for questions about top products, units shipped, or per-customer product mix.', NULL, NULL, NULL, 'cube-model', 'exposed_by -> tool:cube_orders_top_products; has_dimension -> dimension:orders.customer; has_dimension -> dimension:orders.order_date; has_dimension -> dimension:orders.product; has_measure -> measure:orders.distinct_customers; has_measure -> measure:orders.line_count; has_measure -> measure:orders.total_qty; joins -> cube:sales', 'entity:order -> measured_by'),
    ('cube:sales', 'cube', 'sales', 'Sales orders — one row per invoice. Revenue is the booked amount regardless of payment status. Use this cube for any agent or BI question about top customers, revenue by period, ILIKE-style customer-name searches.', NULL, NULL, NULL, 'cube-model', 'exposed_by -> tool:cube_sales_revenue_by_customer; has_dimension -> dimension:sales.customer; has_dimension -> dimension:sales.order_date; has_measure -> measure:sales.avg_order_value; has_measure -> measure:sales.order_count; has_measure -> measure:sales.revenue', 'cube:orders -> joins; entity:customer -> measured_by'),
    ('dbt_model:daily_traffic', 'dbt_model', 'daily_traffic', 'Per-day, per-country traffic rollup (Parquet mart).', NULL, NULL, NULL, 'dbt-project', 'depends_on -> dbt_model:stg_events; exposed_by -> tool:daily_traffic_for_country', NULL),
    ('dbt_model:stg_events', 'dbt_model', 'stg_events', 'Cleaned/typed staging view over the raw dlt events.', NULL, NULL, NULL, 'dbt-project', 'depends_on -> dbt_source:raw.events', 'dbt_model:daily_traffic -> depends_on; dbt_model:top_pages_30d -> depends_on; entity:web_session -> derived_from; term:page_view -> implemented_as'),
    ('dbt_model:top_pages_30d', 'dbt_model', 'top_pages_30d', 'Trailing-30-day page leaderboard (Parquet mart).', NULL, NULL, NULL, 'dbt-project', 'depends_on -> dbt_model:stg_events; exposed_by -> tool:top_pages_30d', NULL),
    ('dbt_source:raw.events', 'dbt_source', 'raw.events', 'One row per captured web event.', NULL, NULL, NULL, 'dbt-project', NULL, 'dbt_model:stg_events -> depends_on'),
    ('dimension:orders.customer', 'dimension', 'orders.customer', 'Customer legal name.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:orders -> has_dimension'),
    ('dimension:orders.order_date', 'dimension', 'orders.order_date', 'Date the order was placed.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:orders -> has_dimension'),
    ('dimension:orders.product', 'dimension', 'orders.product', 'SKU name (e.g. "Widget", "Sprocket", "Gizmo").', NULL, NULL, NULL, 'cube-model', NULL, 'cube:orders -> has_dimension'),
    ('dimension:sales.customer', 'dimension', 'sales.customer', 'Customer legal name (e.g. "Alice GmbH").', NULL, NULL, NULL, 'cube-model', NULL, 'cube:sales -> has_dimension'),
    ('dimension:sales.order_date', 'dimension', 'sales.order_date', 'Date the sale was booked.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:sales -> has_dimension'),
    ('entity:customer', 'entity', 'customer', 'A company that has placed at least one sales order. One row per invoice in the sales table; the same customer appears on many invoices.', 'client, account, buyer', 'ops', 'Customer names are free-text legal names ("Alice GmbH"); there is no customer master table, so name spelling is the identity.', 'authored', 'measured_by -> cube:sales; places -> entity:order; queryable_via -> tool:revenue_by_customer', NULL),
    ('entity:order', 'entity', 'order', 'A product line-item fulfilled for a customer — one row per product per order in the orders table. Carries quantities, not money; the monetary side of the same activity lives on the sales entity''s invoices.', 'line item, purchase', 'ops', 'Orders and sales invoices join on (customer, order_date), not on an order id — the demo schema has no shared key.', 'authored', 'contains -> entity:product; measured_by -> cube:orders', 'entity:customer -> places'),
    ('entity:product', 'entity', 'product', 'A sellable SKU ("Widget", "Sprocket", "Gizmo"). Stock levels and prices live in the inventory catalog on a separate warehouse from the sales activity.', 'sku, item, article', 'ops', 'Unit prices change over time; the current price is the open-ended row in product_price_history, not a column on products. | Sales rows and inventory rows join on product NAME across two different Quack servers.', 'authored', 'queryable_via -> tool:current_prices; queryable_via -> tool:low_stock_items; queryable_via -> tool:price_history_for_product; queryable_via -> tool:product_orders_overview; queryable_via -> tool:top_products', 'entity:order -> contains'),
    ('entity:web_session', 'entity', 'web_session', 'A browser session on the marketing site, identified by session_id in the raw web-events stream. The engineered warehouse (dlt + dbt + Dagster) rolls sessions up into daily traffic and page leaderboards.', 'session, visit', 'marketing', 'Web events are synthetic demo data regenerated by the pipeline; counts change between Dagster materializations.', 'authored', 'derived_from -> dbt_model:stg_events; queryable_via -> tool:daily_traffic_for_country', NULL),
    ('measure:orders.distinct_customers', 'measure', 'orders.distinct_customers', 'Number of distinct customers who placed orders.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:orders -> has_measure'),
    ('measure:orders.line_count', 'measure', 'orders.line_count', 'Number of order line-items.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:orders -> has_measure'),
    ('measure:orders.total_qty', 'measure', 'orders.total_qty', 'Total units shipped across all line-items.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:orders -> has_measure'),
    ('measure:sales.avg_order_value', 'measure', 'sales.avg_order_value', 'Mean revenue per sales order.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:sales -> has_measure'),
    ('measure:sales.order_count', 'measure', 'sales.order_count', 'Number of sales orders.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:sales -> has_measure'),
    ('measure:sales.revenue', 'measure', 'sales.revenue', 'Total booked revenue across all sales orders.', NULL, NULL, NULL, 'cube-model', NULL, 'cube:sales -> has_measure; term:revenue -> implemented_as'),
    ('source:analytics-engineered', 'source', 'analytics-engineered', 'Toolbox source (duckdb-quack), attach alias engineered_remote.', NULL, NULL, NULL, 'tools-config', NULL, 'tool:daily_traffic_for_country -> wired_to; tool:top_pages_30d -> wired_to'),
    ('source:combined-analytics', 'source', 'combined-analytics', 'Toolbox source (duckdb-quack), attach alias sales_remote.', NULL, NULL, NULL, 'tools-config', NULL, 'tool:product_orders_overview -> wired_to'),
    ('source:inventory-quack', 'source', 'inventory-quack', 'Toolbox source (duckdb-quack), attach alias inventory_remote.', NULL, NULL, NULL, 'tools-config', NULL, 'tool:current_prices -> wired_to; tool:inventory_summary -> wired_to; tool:low_stock_items -> wired_to; tool:price_history_for_product -> wired_to'),
    ('source:sales-quack', 'source', 'sales-quack', 'Toolbox source (duckdb-quack), attach alias remote.', NULL, NULL, NULL, 'tools-config', NULL, 'tool:cube_orders_top_products -> wired_to; tool:cube_sales_revenue_by_customer -> wired_to; tool:describe_orders -> wired_to; tool:describe_sales -> wired_to; tool:dev_duckdb_execute_sql -> wired_to; tool:glossary_lookup -> wired_to; tool:list_catalogs -> wired_to; tool:list_remote_schemas -> wired_to; tool:list_remote_tables -> wired_to; tool:ontology_bindings -> wired_to; tool:ontology_describe -> wired_to; tool:ontology_path -> wired_to; tool:ontology_search -> wired_to; tool:revenue_by_customer -> wired_to; tool:summarize_sales -> wired_to; tool:top_products -> wired_to'),
    ('term:active_customer', 'term', 'active_customer', 'A customer with at least one sales invoice in the trailing 90 days. No curated tool implements this window yet — say so rather than substituting all-time revenue.', 'active client', NULL, NULL, 'authored', NULL, NULL),
    ('term:low_stock', 'term', 'low_stock', 'A product whose stock_qty has fallen to or below its reorder_at threshold in the inventory catalog.', 'reorder needed, out of stock risk', NULL, NULL, 'authored', 'implemented_as -> tool:low_stock_items', NULL),
    ('term:page_view', 'term', 'page_view', 'A web event with event_type ''page_view'' in the raw events stream; the unit behind daily traffic counts and the top-pages leaderboard.', 'pageview, page hit', NULL, NULL, 'authored', 'implemented_as -> dbt_model:stg_events', NULL),
    ('term:revenue', 'term', 'revenue', 'The booked invoice amount, regardless of payment status. Lives on sales invoices; quantities shipped are a different question (see top_product).', 'turnover, sales amount', NULL, NULL, 'authored', 'implemented_as -> measure:sales.revenue', NULL),
    ('term:top_product', 'term', 'top_product', 'Products ranked by total units shipped (orders.total_qty), NOT by revenue. A revenue-ranked product list is a different question and has no curated tool today.', 'best seller, top seller', NULL, NULL, 'authored', 'implemented_as -> tool:cube_orders_top_products; implemented_as -> tool:top_products', NULL),
    ('tool:cube_orders_top_products', 'tool', 'cube_orders_top_products', 'Top products by total quantity shipped, with the count of distinct customers per product. Generated from the `orders` cube — measures: orders.total_qty, orders.distinct_customers; dimensions: orders.product. Returns the same rows Cube would for that {measures, dimensions} query against the same warehouse data. To change, edit cube/model/cubes/orders.yml or the slice in cube/codegen.yml and rerun cube/gen_toolbox_from_cube.py.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_cube_backed; wired_to -> source:sales-quack', 'cube:orders -> exposed_by; term:top_product -> implemented_as'),
    ('tool:cube_sales_revenue_by_customer', 'tool', 'cube_sales_revenue_by_customer', 'Total revenue and order count per customer, sorted descending by revenue. Generated from the `sales` cube — measures: sales.revenue, sales.order_count; dimensions: sales.customer. Returns the same rows Cube would for that {measures, dimensions} query against the same warehouse data. To change, edit cube/model/cubes/sales.yml or the slice in cube/codegen.yml and rerun cube/gen_toolbox_from_cube.py.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_cube_backed; wired_to -> source:sales-quack', 'cube:sales -> exposed_by'),
    ('tool:current_prices', 'tool', 'current_prices', 'Join the products table with the current (open-ended) row in product_price_history so each SKU is paired with its active price plus the date the current price went into effect. Demonstrates a join between a normal table and a parquet-backed view, both on the same remote Quack server.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:inventory_readonly; wired_to -> source:inventory-quack', 'entity:product -> queryable_via'),
    ('tool:daily_traffic_for_country', 'tool', 'daily_traffic_for_country', 'Daily traffic counts for one country, latest dates first. Country code is ISO-3166-1 alpha-2 (DE, FR, GB, US, ES, IT, NL). Powered by the `daily_traffic` dbt model.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_engineered; wired_to -> source:analytics-engineered', 'dbt_model:daily_traffic -> exposed_by; entity:web_session -> queryable_via'),
    ('tool:describe_orders', 'tool', 'describe_orders', 'Return the column names, types, and nullability of the remote.main.orders table.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_metadata; wired_to -> source:sales-quack', NULL),
    ('tool:describe_sales', 'tool', 'describe_sales', 'Return the column names, types, and nullability of the remote.main.sales table.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_metadata; wired_to -> source:sales-quack', NULL),
    ('tool:dev_duckdb_execute_sql', 'tool', 'dev_duckdb_execute_sql', 'Run an arbitrary read-only SQL statement against the analytics catalog. Development and human-in-the-loop debugging only.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_dev; wired_to -> source:sales-quack', NULL),
    ('tool:glossary_lookup', 'tool', 'glossary_lookup', 'The reviewed business definition of a term, matched by exact term or synonym (case-insensitive), with provenance (who decided it, when). Cite the definition you used in your answer; if a term is not in the glossary, say so rather than inventing a definition.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:ontology; wired_to -> source:sales-quack', NULL),
    ('tool:inventory_summary', 'tool', 'inventory_summary', 'Per-category totals: number of distinct products, total units in stock, average unit price.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:inventory_readonly; wired_to -> source:inventory-quack', NULL),
    ('tool:list_catalogs', 'tool', 'list_catalogs', 'List the catalogs the Toolbox-side DuckDB can see. Useful as the first call when an agent is exploring an unfamiliar deployment.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_metadata; wired_to -> source:sales-quack', NULL),
    ('tool:list_remote_schemas', 'tool', 'list_remote_schemas', 'List the schemas in the remote DuckDB''s current database.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_metadata; wired_to -> source:sales-quack', NULL),
    ('tool:list_remote_tables', 'tool', 'list_remote_tables', 'List the base tables and views in the remote `main` schema. The result is a row per table with name and table_type.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_metadata; wired_to -> source:sales-quack', NULL),
    ('tool:low_stock_items', 'tool', 'low_stock_items', 'List products whose current stock has fallen at or below their reorder threshold. Read-only; reads from a separate Quack server than the sales tools above.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:inventory_readonly; wired_to -> source:inventory-quack', 'entity:product -> queryable_via; term:low_stock -> implemented_as'),
    ('tool:ontology_bindings', 'tool', 'ontology_bindings', 'The implementation surface of a business entity or glossary term: every cube, measure, tool, dbt model/source, toolset, and Toolbox source it is connected to, with the connection path and hop count. Use this to ROUTE — after resolving what the user means, pick the lowest-hop tool from here instead of guessing.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:ontology; wired_to -> source:sales-quack', NULL),
    ('tool:ontology_describe', 'tool', 'ontology_describe', 'Full card for one ontology node, matched by exact name (or ''<kind>:<name>'' id, case-insensitive): definition, synonyms, owner, caveats, provenance, and its relations in both directions. Caveats are the "gotchas" a correct answer must respect — repeat the relevant ones to the user.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:ontology; wired_to -> source:sales-quack', NULL),
    ('tool:ontology_path', 'tool', 'ontology_path', 'How two named ontology nodes are connected: the shortest path (up to 4 hops, direction-agnostic) between them, as a readable chain of relations. Both arguments are exact node names. An empty result means no connection within 4 hops — treat the concepts as unrelated rather than forcing a join.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:ontology; wired_to -> source:sales-quack', NULL),
    ('tool:ontology_search', 'tool', 'ontology_search', 'Find business entities, glossary terms, cubes, measures, tools, dbt models, and toolsets whose name, synonyms, or description match a case-insensitive substring. Use this FIRST to resolve a business term before picking a data tool; follow up with ontology_describe or ontology_bindings on a hit. The pattern is a plain substring; do not include SQL wildcards yourself.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:ontology; wired_to -> source:sales-quack', NULL),
    ('tool:price_history_for_product', 'tool', 'price_history_for_product', 'Return the full price history (validity windows + change reason) for one product. The pattern is a plain case-insensitive substring; do not include SQL wildcards yourself. Rows are backed by a parquet file mounted next to the remote DuckDB.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:inventory_readonly; wired_to -> source:inventory-quack', 'entity:product -> queryable_via'),
    ('tool:product_orders_overview', 'tool', 'product_orders_overview', 'For each product in the inventory catalog, show its stock situation plus the total quantity ordered across all sales. Joins inventory_remote.products with sales_remote.orders on product name. Read-only.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:cross_catalog; wired_to -> source:combined-analytics', 'entity:product -> queryable_via'),
    ('tool:revenue_by_customer', 'tool', 'revenue_by_customer', 'Return revenue and order-count for customers whose name matches a case-insensitive pattern. The pattern is a plain substring; do not include SQL wildcards yourself. Read-only and limited to the sales mart.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_readonly; wired_to -> source:sales-quack', 'entity:customer -> queryable_via'),
    ('tool:summarize_sales', 'tool', 'summarize_sales', 'Per-column statistics for remote.main.sales (min, max, avg, std, quartiles, distinct counts, null percentages).', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_metadata; wired_to -> source:sales-quack', NULL),
    ('tool:top_pages_30d', 'tool', 'top_pages_30d', 'Top pages by views in the trailing 30 days, with distinct user and session counts. Powered by the `top_pages_30d` dbt model in dagster/dbt_project/models/.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_engineered; wired_to -> source:analytics-engineered', 'dbt_model:top_pages_30d -> exposed_by'),
    ('tool:top_products', 'tool', 'top_products', 'List the top products by total quantity sold across all orders. Read-only and limited to the sales mart.', NULL, NULL, NULL, 'tools-config', 'in_toolset -> toolset:analytics_readonly; wired_to -> source:sales-quack', 'entity:product -> queryable_via; term:top_product -> implemented_as'),
    ('toolset:analytics_cube_backed', 'toolset', 'analytics_cube_backed', NULL, NULL, NULL, NULL, 'tools-config', NULL, 'tool:cube_orders_top_products -> in_toolset; tool:cube_sales_revenue_by_customer -> in_toolset'),
    ('toolset:analytics_dev', 'toolset', 'analytics_dev', NULL, NULL, NULL, NULL, 'tools-config', NULL, 'tool:dev_duckdb_execute_sql -> in_toolset'),
    ('toolset:analytics_engineered', 'toolset', 'analytics_engineered', NULL, NULL, NULL, NULL, 'tools-config', NULL, 'tool:daily_traffic_for_country -> in_toolset; tool:top_pages_30d -> in_toolset'),
    ('toolset:analytics_metadata', 'toolset', 'analytics_metadata', NULL, NULL, NULL, NULL, 'tools-config', NULL, 'tool:describe_orders -> in_toolset; tool:describe_sales -> in_toolset; tool:list_catalogs -> in_toolset; tool:list_remote_schemas -> in_toolset; tool:list_remote_tables -> in_toolset; tool:summarize_sales -> in_toolset'),
    ('toolset:analytics_readonly', 'toolset', 'analytics_readonly', NULL, NULL, NULL, NULL, 'tools-config', NULL, 'tool:revenue_by_customer -> in_toolset; tool:top_products -> in_toolset'),
    ('toolset:cross_catalog', 'toolset', 'cross_catalog', NULL, NULL, NULL, NULL, 'tools-config', NULL, 'tool:product_orders_overview -> in_toolset'),
    ('toolset:inventory_readonly', 'toolset', 'inventory_readonly', NULL, NULL, NULL, NULL, 'tools-config', NULL, 'tool:current_prices -> in_toolset; tool:inventory_summary -> in_toolset; tool:low_stock_items -> in_toolset; tool:price_history_for_product -> in_toolset'),
    ('toolset:ontology', 'toolset', 'ontology', NULL, NULL, NULL, NULL, 'tools-config', NULL, 'tool:glossary_lookup -> in_toolset; tool:ontology_bindings -> in_toolset; tool:ontology_describe -> in_toolset; tool:ontology_path -> in_toolset; tool:ontology_search -> in_toolset');
