INSERT INTO ontology_glossary VALUES
    ('active_customer', 'A customer with at least one sales invoice in the trailing 90 days. No curated tool implements this window yet — say so rather than substituting all-time revenue.', 'active client', 'ops, 2026-06-11'),
    ('low_stock', 'A product whose stock_qty has fallen to or below its reorder_at threshold in the inventory catalog.', 'reorder needed, out of stock risk', 'ops, 2026-06-11'),
    ('page_view', 'A web event with event_type ''page_view'' in the raw events stream; the unit behind daily traffic counts and the top-pages leaderboard.', 'pageview, page hit', 'marketing, 2026-06-11'),
    ('revenue', 'The booked invoice amount, regardless of payment status. Lives on sales invoices; quantities shipped are a different question (see top_product).', 'turnover, sales amount', 'ops, 2026-06-11'),
    ('top_product', 'Products ranked by total units shipped (orders.total_qty), NOT by revenue. A revenue-ranked product list is a different question and has no curated tool today.', 'best seller, top seller', 'ops, 2026-06-11');
INSERT INTO ontology_bindings VALUES
    ('entity:customer', 'customer', 'entity', 'cube', 'orders', 'Product line-items per order — one row per product fulfilled. Use this cube for questions about top products, units shipped, or per-customer product mix.', 'entity:customer -[places]-> entity:order -[measured_by]-> cube:orders', 2),
    ('entity:customer', 'customer', 'entity', 'cube', 'sales', 'Sales orders — one row per invoice. Revenue is the booked amount regardless of payment status. Use this cube for any agent or BI question about top customers, revenue by period, ILIKE-style customer-name searches.', 'entity:customer -[measured_by]-> cube:sales', 1),
    ('entity:customer', 'customer', 'entity', 'cube', 'sales', 'Sales orders — one row per invoice. Revenue is the booked amount regardless of payment status. Use this cube for any agent or BI question about top customers, revenue by period, ILIKE-style customer-name searches.', 'entity:customer -[places]-> entity:order -[measured_by]-> cube:orders -[joins]-> cube:sales', 3),
    ('entity:customer', 'customer', 'entity', 'measure', 'orders.distinct_customers', 'Number of distinct customers who placed orders.', 'entity:customer -[places]-> entity:order -[measured_by]-> cube:orders -[has_measure]-> measure:orders.distinct_customers', 3),
    ('entity:customer', 'customer', 'entity', 'measure', 'orders.line_count', 'Number of order line-items.', 'entity:customer -[places]-> entity:order -[measured_by]-> cube:orders -[has_measure]-> measure:orders.line_count', 3),
    ('entity:customer', 'customer', 'entity', 'measure', 'orders.total_qty', 'Total units shipped across all line-items.', 'entity:customer -[places]-> entity:order -[measured_by]-> cube:orders -[has_measure]-> measure:orders.total_qty', 3),
    ('entity:customer', 'customer', 'entity', 'measure', 'sales.avg_order_value', 'Mean revenue per sales order.', 'entity:customer -[measured_by]-> cube:sales -[has_measure]-> measure:sales.avg_order_value', 2),
    ('entity:customer', 'customer', 'entity', 'measure', 'sales.order_count', 'Number of sales orders.', 'entity:customer -[measured_by]-> cube:sales -[has_measure]-> measure:sales.order_count', 2),
    ('entity:customer', 'customer', 'entity', 'measure', 'sales.revenue', 'Total booked revenue across all sales orders.', 'entity:customer -[measured_by]-> cube:sales -[has_measure]-> measure:sales.revenue', 2),
    ('entity:customer', 'customer', 'entity', 'source', 'sales-quack', 'Toolbox source (duckdb-quack), attach alias remote.', 'entity:customer -[measured_by]-> cube:sales -[exposed_by]-> tool:cube_sales_revenue_by_customer -[wired_to]-> source:sales-quack', 3),
    ('entity:customer', 'customer', 'entity', 'source', 'sales-quack', 'Toolbox source (duckdb-quack), attach alias remote.', 'entity:customer -[queryable_via]-> tool:revenue_by_customer -[wired_to]-> source:sales-quack', 2),
    ('entity:customer', 'customer', 'entity', 'tool', 'cube_orders_top_products', 'Top products by total quantity shipped, with the count of distinct customers per product. Generated from the `orders` cube — measures: orders.total_qty, orders.distinct_customers; dimensions: orders.product. Returns the same rows Cube would for that {measures, dimensions} query against the same warehouse data. To change, edit cube/model/cubes/orders.yml or the slice in cube/codegen.yml and rerun cube/gen_toolbox_from_cube.py.', 'entity:customer -[places]-> entity:order -[measured_by]-> cube:orders -[exposed_by]-> tool:cube_orders_top_products', 3),
    ('entity:customer', 'customer', 'entity', 'tool', 'cube_sales_revenue_by_customer', 'Total revenue and order count per customer, sorted descending by revenue. Generated from the `sales` cube — measures: sales.revenue, sales.order_count; dimensions: sales.customer. Returns the same rows Cube would for that {measures, dimensions} query against the same warehouse data. To change, edit cube/model/cubes/sales.yml or the slice in cube/codegen.yml and rerun cube/gen_toolbox_from_cube.py.', 'entity:customer -[measured_by]-> cube:sales -[exposed_by]-> tool:cube_sales_revenue_by_customer', 2),
    ('entity:customer', 'customer', 'entity', 'tool', 'current_prices', 'Join the products table with the current (open-ended) row in product_price_history so each SKU is paired with its active price plus the date the current price went into effect. Demonstrates a join between a normal table and a parquet-backed view, both on the same remote Quack server.', 'entity:customer -[places]-> entity:order -[contains]-> entity:product -[queryable_via]-> tool:current_prices', 3),
    ('entity:customer', 'customer', 'entity', 'tool', 'low_stock_items', 'List products whose current stock has fallen at or below their reorder threshold. Read-only; reads from a separate Quack server than the sales tools above.', 'entity:customer -[places]-> entity:order -[contains]-> entity:product -[queryable_via]-> tool:low_stock_items', 3),
    ('entity:customer', 'customer', 'entity', 'tool', 'price_history_for_product', 'Return the full price history (validity windows + change reason) for one product. The pattern is a plain case-insensitive substring; do not include SQL wildcards yourself. Rows are backed by a parquet file mounted next to the remote DuckDB.', 'entity:customer -[places]-> entity:order -[contains]-> entity:product -[queryable_via]-> tool:price_history_for_product', 3),
    ('entity:customer', 'customer', 'entity', 'tool', 'product_orders_overview', 'For each product in the inventory catalog, show its stock situation plus the total quantity ordered across all sales. Joins inventory_remote.products with sales_remote.orders on product name. Read-only.', 'entity:customer -[places]-> entity:order -[contains]-> entity:product -[queryable_via]-> tool:product_orders_overview', 3),
    ('entity:customer', 'customer', 'entity', 'tool', 'revenue_by_customer', 'Return revenue and order-count for customers whose name matches a case-insensitive pattern. The pattern is a plain substring; do not include SQL wildcards yourself. Read-only and limited to the sales mart.', 'entity:customer -[queryable_via]-> tool:revenue_by_customer', 1),
    ('entity:customer', 'customer', 'entity', 'tool', 'top_products', 'List the top products by total quantity sold across all orders. Read-only and limited to the sales mart.', 'entity:customer -[places]-> entity:order -[contains]-> entity:product -[queryable_via]-> tool:top_products', 3),
